def range_summary(nums):
    if not nums:
        return ''

    seen = set()
    ranges = []
    prev, start = None, None

    for num in sorted(set(nums)):
        if num not in seen or (prev is not None and num == prev + 1):
            if prev is not None:
                if start is None:
                    start = prev
                if num - prev > 1:
                    ranges.append(f'{start}-{prev}' if start != prev else f'{start}')
            else:
                start = num
        else:
            if start is not None and (num - start > 1 or num == prev):
                ranges.append(f'{start}-{prev}' if start != prev else f'{start}')
                start = None

        seen.add(num)
        prev = num

    for num in sorted(set(nums)):
        if start is not None and num == start:
            ranges.append(f'{start}')

    return ','.join(ranges)
